--随机n个[low,high]范围的整数
function MathUtil:randomIntRepeat(low, high, n)
    local result = {}
    for i = 1, n do
        table.insert(result, math.random(low, high))
    end
    return result
end

function MathUtil:createTable(low, high)
    local result = {}
    for i = low, high do
        table.insert(result, i)
    end
    return result
end

--随机n个[low,high]范围的不重复的整数
function MathUtil:randomIntNoRepeat(low, high, n)
    local size = high - low + 1
    if n > size then
        return nil
    end

    local tb = MathUtil:createTable(low, high)

    local result = {}
    for i = 1, n do
        local index = math.random(#tb)
        tb[index], tb[#tb] = tb[#tb], tb[index]
        table.insert(result, tb[#tb])
        table.remove(tb)
    end
    return result
end

--在矩形范围内随机count个不重复的点
function MathUtil:randomInRect(minX, maxX, minZ, maxZ, count)
    local result = {}

    if (maxX - minX + 1) * (maxZ - minZ + 1) < count then
        return result
    end

    local index = 1
    while(index <= count)
    do
        local randomX = math.random(minX, maxX)
        local randomZ = math.random(minZ, maxZ)
        local pt = PointUtil:newPoint(randomX, randomZ)
        if PointUtil:isTableHavePoint(result, pt) == false then
            table.insert(result, pt)
            index = index + 1
        end
    end

    return result
end

