--在圆内随机一个点
function MathUtil:randomInCircle(pos, radius)
    local resultX = math.random(-radius, radius)
    local resultY = math.sqrt(math.pow(radius, 2) - math.pow(resultX, 2))
    resultY = math.random(-resultY, resultY)
    return VectorUtil.newVector3(resultX + pos.x, pos.y, resultY + pos.z)
end

--3d点距离的平方
function MathUtil:distanceSquare3d(pos1, pos2)
    local result = math.pow((pos1.x - pos2.x), 2) + math.pow((pos1.y - pos2.y), 2) + math.pow((pos1.z - pos2.z), 2)
    return result
end

--检测是否在距离内
function MathUtil:checkDisLessThan(pos1, pos2, dis)
    return MathUtil:distanceSquare3d(pos1, pos2) < math.pow(dis, 2)
end

return MathUtil